public static LocalDate fromDateFields(Date date) {
    if (date == null) {
        throw new IllegalArgumentException("The date must not be null");
    }
    Calendar calendar = Calendar.getInstance();
    calendar.setTime(date);
    int year = calendar.get(Calendar.YEAR);
    if (calendar.get(Calendar.ERA) == GregorianCalendar.BC) {
        year = 1 - year;
    }
    return new LocalDate(
        year,
        calendar.get(Calendar.MONTH) + 1,
        calendar.get(Calendar.DAY_OF_MONTH)
    );
}

public static LocalDate fromCalendarFields(Calendar calendar) {
    if (calendar == null) {
        throw new IllegalArgumentException("The calendar must not be null");
    }
    int year = calendar.get(Calendar.YEAR);
    int month = calendar.get(Calendar.MONTH) + 1;
    int dayOfMonth = calendar.get(Calendar.DAY_OF_MONTH);

    // Check if the calendar is a GregorianCalendar to handle BCE years correctly
    if (calendar instanceof GregorianCalendar) {
        int era = calendar.get(Calendar.ERA);
        if (era == GregorianCalendar.BC) {
            year = 1 - year;
        }
    }

    try {
        return new LocalDate(year, month, dayOfMonth);
    } catch (IllegalArgumentException e) {
        throw new IllegalArgumentException("The date is invalid for the ISO chronology", e);
    }
}

public static LocalDate fromCalendarFields(Calendar calendar) {
    if (calendar == null) {
        throw new IllegalArgumentException("The calendar must not be null");
    }
    if (!(calendar instanceof GregorianCalendar)) {
        throw new IllegalArgumentException("The calendar must be an instance of GregorianCalendar");
    }
    int year = calendar.get(Calendar.YEAR);
    int era = calendar.get(Calendar.ERA);
    int yearOfEra = (era == GregorianCalendar.BC) ? 1 - year : year;
    return new LocalDate(
        yearOfEra,
