        calendar.get(Calendar.DAY_OF_MONTH)
    );
}

public static LocalDate fromCalendarFields(Calendar calendar) {
    if (calendar == null) {
        throw new IllegalArgumentException("The calendar must not be null");
    }
    int year = calendar.get(Calendar.YEAR);
    int era = calendar.get(Calendar.ERA);
    if (era == GregorianCalendar.BC) {
        year = 1 - year;
    }
    // Use calendar.getActualMaximum to handle leap years and month variations
    int month = calendar.get(Calendar.MONTH) + 1;
    int dayOfMonth = Math.min(calendar.get(Calendar.DAY_OF_MONTH), calendar.getActualMaximum(Calendar.DAY_OF_MONTH));
    try {
        return new LocalDate(year, month, dayOfMonth);
    } catch (IllegalArgumentException e) {
        throw new IllegalArgumentException("The date is invalid for the ISO chronology", e);
    }
}

public static LocalDate fromCalendarFields(Calendar calendar) {
